#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,V=1e6+10;

int T,n,a[N],lst[V];
long long s[N],f[N][2];

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
            scanf("%d",&a[i]);
        memset(lst,0,sizeof(lst));
        for(int i=1;i<=n;i++){
            f[i][0]=max(f[i-1][0],f[i-1][1])+(a[i]==a[i-1])*a[i];
            int p=lst[a[i]];
            if(p) f[i][1]=max(max(f[i-1][0],f[i-1][1]),f[p+1][1]+a[i]+s[i-1]-s[p+1]);
            else f[i][1]=max(f[i-1][0],f[i-1][1]);
            s[i]=(a[i]==a[i-1])*a[i]+s[i-1];
            lst[a[i-1]]=i-1;
        }
        printf("%lld\n",max(f[n][0],f[n][1]));
    }
    return 0;
}
